reg [31:0] r[4];
reg [1:0] rd;
reg [1:0] step;
always @(posedge CLK) begin
  case (step)
    1: if (rd != 0) r[rd] <= 1;
    2: if (r[1] == 1) LED <= 1;
  endcase
end

reg [31:0] r[4];
reg [1:0] rd;
reg [1:0] step;
initial rd = 0;
always @(posedge CLK) begin
  case (step)
    0: rd <= 0;
    1: if (rd != 0) r[rd] <= 1;
    2: rd <= 1;
  endcase
end

